// Unified RSS Filter (24h) — source name hardcoded per branch
const data = items[0].json;
const sourceName = 'u.today';

const first = (v) => Array.isArray(v) ? v[0] : v;
const toArray = (v) => (v == null ? [] : (Array.isArray(v) ? v : [v]));
const stripHtml = (s) => (s || '').replace(/<[^>]*>/g, '').trim();
const decodeEntities = (s) =>
  (s || '')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"').replace(/&#39;/g, "'");

const now = Date.now();
const cutoff = now - 24 * 60 * 60 * 1000;

const channel = first(data?.rss?.channel) || data?.channel;
const rssItems = toArray(channel?.item);

const cleaned = rssItems
  .map((it) => {
    const title = stripHtml(first(it.title) || '');
    const url = decodeEntities(first(it.link) || '');
    const pubDateRaw = first(it.pubDate) || null;
    const publishedAt = pubDateRaw ? new Date(pubDateRaw) : null;
    const ts = publishedAt && !isNaN(publishedAt.getTime()) ? publishedAt.getTime() : null;
    const summary = stripHtml(first(it.description) || '');
    const media = first(it['media:content']);
    const imageUrl = media?.$?.url ? decodeEntities(media.$.url) : null;
    const guidVal = first(it.guid);
    const guid = typeof guidVal === 'object'
      ? (guidVal?._ || guidVal?.['#text'] || null)
      : (guidVal || null);
    return { source: sourceName, title: title || null, url: url || null,
      publishedAt: ts ? new Date(ts).toISOString() : null,
      summary: summary || null, imageUrl, guid, _ts: ts };
  })
  .filter((a) => a.title && a.url && a._ts && a._ts >= cutoff)
  .filter((a, idx, arr) => arr.findIndex((x) => x.url === a.url) === idx)
  .sort((a, b) => a._ts - b._ts)
  .map(({ _ts, ...rest }) => rest);

return cleaned.map((a) => ({ json: a }));

