// n8n Code Node (Run Once for All Items)
// RAW NEWS ONLY – no pricechanges, no max stories
// Output: one-line agent-ready string (no line breaks)

var nowIso = new Date().toISOString();
var items = $input.all();

var stories = [];

// Collect stories (any count)
for (var i = 0; i < items.length; i++) {
  var j = items[i].json || {};
  if (j.title && j.summary) {
    stories.push({
      title: String(j.title).replace(/\s+/g, " ").trim(),
      summary: String(j.summary).replace(/\s+/g, " ").trim()
    });
  }
}

// Build one-line string
var parts = [];
for (var s = 0; s < stories.length; s++) {
  var n = s + 1;
  parts.push(n + ") " + stories[s].title + " — summary: " + stories[s].summary);
}

var text =
  "CRYPTO NEWS – RAW INPUT | " +
  "Generated (UTC): " + nowIso +
  " | Stories: " + stories.length +
  (parts.length ? " | " + parts.join(" | ") : "");

return [{
  json: { text: text },
  pairedItem: { item: 0 }
}];

// ==============================
// NEWS CLUSTERING + SCORING (n8n compatible)
// Input: items[].json = {source,title,summary,url,publishedAt}
// Output: 1 best item per cluster, then keep ~50% by score (with safety minimum)
// ==============================

// ---------- PARAMS ----------
const PARAMS = {
  // Clustering (moderately conservative -> avoids "everything Bitcoin" collapsing into 1 cluster)
  JACCARD_TH: 0.26,
  MIN_OVERLAP: 4,
  SUMMARY_CHARS: 800,

  // Token filtering (helps cluster quality)
  TOO_COMMON_RATIO: 0.35,  // drop tokens appearing in >35% of docs
  MIN_DF: 2,               // keep tokens that appear at least twice (if possible)

  // Output shaping
  TARGET_KEEP_RATIO: 0.50, // keep ~50% of clustered results
  MIN_RESULTS: 12,         // safety: don't collapse to a tiny list unless there truly aren't enough
  MAX_RESULTS: 30,         // hard cap

  // Scoring weights
  FACT_EVENT_BOOST: 1.0,   // multiplier for event keywords
};

// ---------- SOURCE WEIGHTS ----------
const SOURCE_WEIGHT = {
  coindesk: 1.25,
  cointelegraph: 1.05,
  thedefiant: 1.05,
  cryptonews: 0.80,
  "u.today": 0.70,
};

// ---------- HARD EXCLUDES (ONLY the truly unwanted formats) ----------
const HARD_EXCLUDE_TITLE_PATTERNS = [
  /\bhere['’]?s what happened in crypto today\b/i,
  /\bwhat happened in crypto today\b/i,
  /\bcrypto digest\b/i,
  /\bmorning crypto report\b/i,
  /\b\[live\]\b/i,
  /\blive crypto news\b/i,
  /\byour day-ahead look\b/i,     // CoinDesk daybook-ish
];

// The EXACT type you said must never appear:
const HARD_EXCLUDE_COMMENTARY_ROUNDUP =
  /\bhere\s+is\s+what\s+.*\s+are\s+saying\b/i;

// Optionally treat “podcast/video” as non-news (kept as hard exclude to reduce noise)
const HARD_EXCLUDE_CONTENT_TYPE =
  /\b(podcast|podcasts|video|videos)\b/i;

function hardExclude(it) {
  const t = (it.title || "");
  const s = (it.summary || "");
  const blob = `${t} ${s}`;

  if (HARD_EXCLUDE_TITLE_PATTERNS.some(re => re.test(t))) return true;
  if (HARD_EXCLUDE_COMMENTARY_ROUNDUP.test(t)) return true; // your banned example
  if (HARD_EXCLUDE_CONTENT_TYPE.test(blob)) return true;

  return false;
}

// ---------- SOFT "NON-FACT" SIGNALS (NOT excluded, only penalized) ----------
const SOFT_SPECULATION_PATTERNS = [
  /\bprice prediction\b/i,
  /\bforecast\b/i,
  /\bwhat['’]?s next\b/i,
  /\bcould\b/i,
  /\bmay\b/i,
  /\bmight\b/i,
  /\bexpected\b/i,
  /\btargets?\b/i,
  /\bsigns?\b/i,
  /\bwarning\b/i,
  /\bwarns?\b/i,
  /\bhow long until\b/i,
  /\bwill\b/i,
];

function speculationPenalty(title, summary) {
  const t = title || "";
  const s = summary || "";
  const blob = `${t} ${s}`;

  let p = 0;

  // Questions are usually “what next / will it …”
  if (/\?/.test(t)) p += 4;

  // “Price prediction” is extra speculative
  if (/\bprice prediction\b/i.test(blob)) p += 6;

  // mild speculative language
  for (const re of SOFT_SPECULATION_PATTERNS) {
    if (re.test(blob)) { p += 1; }
  }

  // cap penalty so it doesn't nuke everything
  return Math.min(p, 10);
}

// ---------- KEYWORDS (EVENT / FACT SIGNALS) ----------
const KEYWORDS = [
  // Policy / regulation / legal
  { re: /\b(cftc|sec|lawsuit|court|ruling|settlement|ban|bill|senate|house|probe|regulation|market structure)\b/i, pts: 7 },
  // Big institutions / banks / treasuries
  { re: /\b(deutsche bank|jpmorgan|treasury|bank|anchorage|custodial|custody|institutional)\b/i, pts: 5 },
  // ETFs / derivatives / flows
  { re: /\b(etf|outflows?|inflows?|open interest|liquidations?|futures|margin longs)\b/i, pts: 5 },
  // Stablecoins
  { re: /\b(stablecoin|usdc|usdt|tether|circle|depeg|reserves?)\b/i, pts: 4 },
  // Security incidents
  { re: /\b(hack|exploit|breach|attack|dark web|fbi)\b/i, pts: 6 },
  // Tokenization / RWA / infra
  { re: /\b(tokeni[sz]ed|tokeni[sz]ation|rwa|real world assets|settlement|layer-2|l2|blockchain)\b/i, pts: 4 },
  // Major assets (small boost; avoid dominating)
  { re: /\b(bitcoin|btc)\b/i, pts: 1.5 },
  { re: /\b(ethereum|eth)\b/i, pts: 1.0 },
  { re: /\b(xrp|solana|dogecoin|shib|cardano|bnb)\b/i, pts: 0.8 },
];

function keywordPoints(text) {
  let pts = 0;
  for (const k of KEYWORDS) if (k.re.test(text)) pts += k.pts;
  return pts * PARAMS.FACT_EVENT_BOOST;
}

// Numeric facts bonus: $xxxM/B, %, dates, etc.
function numericFactsBonus(text) {
  let b = 0;
  if (/\$\s?\d/.test(text) || /\b\d+(\.\d+)?\s?(million|billion|m|bn)\b/i.test(text)) b += 2.5;
  if (/\b\d+(\.\d+)?\s?%\b/.test(text)) b += 1.5;
  if (/\b(q[1-4]|quarter|q4|q3|q2|q1)\b/i.test(text)) b += 1.0;
  return b;
}

// Recency bonus
function recencyPoints(dateStr) {
  const ts = new Date(dateStr).getTime();
  if (!ts) return 0;
  const mins = (Date.now() - ts) / 60000;
  if (mins <= 60) return 5;
  if (mins <= 360) return 3;
  if (mins <= 1440) return 1.5;
  if (mins <= 4320) return 0.5; // last 3 days
  return 0;
}

// ---------- TOKENIZATION ----------
const STOPWORDS = new Set([
  "the","a","an","and","or","to","of","in","on","for","with","as","at","by","from",
  "is","are","was","were","be","been","it","this","that","these","those",
  "today","report","update","markets","market","crypto","price",
  "here","because","before","after","into","over","under","near","amid",
  "says","said" // reduces “quote style” clustering noise
]);

function normalizeToken(w) {
  // strip surrounding punctuation already mostly removed, but keep safe
  w = w.toLowerCase();

  // Drop pure numbers
  if (/^\d+$/.test(w)) return null;

  // Keep short alnum like "l2"
  if (/^[a-z]\d$/.test(w)) return w;

  // If token contains digits (e.g., usd70), drop digits part to reduce clustering on numbers
  if (/[0-9]/.test(w)) {
    const letters = w.replace(/[0-9]/g, "");
    if (letters.length >= 3) return letters;
    // else ignore noisy tokens like "70k", "2k"
    return null;
  }

  return w;
}

function tokenize(text) {
  return (text || "")
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, " ")
    .split(/\s+/)
    .map(normalizeToken)
    .filter(w =>
      w &&
      w.length >= 3 &&
      !STOPWORDS.has(w)
    );
}

// ---------- CLUSTER HELPERS ----------
function jaccard(a, b) {
  let i = 0;
  for (const x of a) if (b.has(x)) i++;
  const u = a.size + b.size - i;
  return u ? i / u : 0;
}

function overlapCount(a, b) {
  let c = 0;
  for (const x of a) if (b.has(x)) c++;
  return c;
}

// Create a readable cluster key (top tokens)
function buildClusterKey(tokenSet, freqMap) {
  const tokens = Array.from(tokenSet);

  // prefer rarer tokens (approx IDF) => sort by increasing DF
  tokens.sort((t1, t2) => (freqMap.get(t1) || 9999) - (freqMap.get(t2) || 9999));

  // pick a few
  return tokens.slice(0, 6).join(" | ");
}

// ---------- URL CANONICALIZATION (strip utm_...) ----------
function canonicalUrl(url) {
  try {
    const u = new URL(url);
    // remove utm_* params
    for (const k of Array.from(u.searchParams.keys())) {
      if (k.toLowerCase().startsWith("utm_")) u.searchParams.delete(k);
    }
    // normalize
    u.hash = "";
    return u.toString();
  } catch {
    return url;
  }
}

// ==============================
// MAIN
// ==============================

// 1) Canonical URL dedupe + HARD EXCLUDES
const seen = new Set();
const raw = [];
for (const it of items.map(i => i.json)) {
  if (!it?.title || !it?.url) continue;

  const cu = canonicalUrl(it.url);
  if (seen.has(cu)) continue;
  if (hardExclude(it)) continue;

  seen.add(cu);
  raw.push({ ...it, url: cu });
}

// 2) Build token sets + DF stats
const tokenSets = [];
const freq = new Map();

for (const a of raw) {
  const set = new Set(tokenize(`${a.title} ${(a.summary || "").slice(0, PARAMS.SUMMARY_CHARS)}`));
  tokenSets.push(set);
  for (const t of set) freq.set(t, (freq.get(t) || 0) + 1);
}

// Filter out too-common tokens (keeps clustering meaningful)
const tooCommon = Math.ceil(raw.length * PARAMS.TOO_COMMON_RATIO);

function filteredSet(set) {
  const out = new Set();
  for (const t of set) {
    const f = freq.get(t) || 0;
    // if dataset is small, don't over-filter: allow MIN_DF=1 fallback
    const minDf = raw.length < 25 ? 1 : PARAMS.MIN_DF;
    if (f >= minDf && f <= tooCommon) out.add(t);
  }
  return out;
}

const filteredTokenSets = tokenSets.map(filteredSet);

// 3) Clustering
const clusters = [];

for (let i = 0; i < raw.length; i++) {
  const tok = filteredTokenSets[i].size ? filteredTokenSets[i] : tokenSets[i];

  let bestIdx = -1;
  let bestSim = 0;

  for (let j = 0; j < clusters.length; j++) {
    const ov = overlapCount(tok, clusters[j].tokens);
    const jac = jaccard(tok, clusters[j].tokens);

    // gate
    if (ov < PARAMS.MIN_OVERLAP && jac < PARAMS.JACCARD_TH) continue;

    // similarity score
    const sim = Math.max(jac, ov / 12);
    if (sim > bestSim) {
      bestSim = sim;
      bestIdx = j;
    }
  }

  if (bestIdx === -1) {
    clusters.push({ tokens: new Set(tok), items: [raw[i]] });
  } else {
    clusters[bestIdx].items.push(raw[i]);
    tok.forEach(t => clusters[bestIdx].tokens.add(t));
  }
}

// 4) Score each item; pick best representative per cluster
function scoreItem(a) {
  const text = `${a.title} ${a.summary || ""}`;

  const sw = SOURCE_WEIGHT[(a.source || "").toLowerCase()] ?? 0.85;

  const base = sw * 6; // small, so keywords & facts matter more
  const kpts = keywordPoints(text);
  const nbonus = numericFactsBonus(text);
  const rpts = recencyPoints(a.publishedAt);

  const pen = speculationPenalty(a.title, a.summary);

  // final score
  const score = base + kpts + nbonus + rpts - pen;

  return Number(score.toFixed(2));
}

const results = [];

for (const c of clusters) {
  let best = null;
  for (const a of c.items) {
    const score = scoreItem(a);
    if (!best || score > best.score) {
      best = {
        ...a,
        score,
        clusterSize: c.items.length,
        clusterKey: buildClusterKey(c.tokens, freq),
      };
    }
  }
  if (best) results.push(best);
}

results.sort((a, b) => b.score - a.score);

// 5) Keep ~50% ONLY ONCE (no MIN_SCORE), with minimum safeguard
const total = results.length;

const keepNRaw = Math.round(total * PARAMS.TARGET_KEEP_RATIO);
const keepN = Math.min(
  PARAMS.MAX_RESULTS,
  Math.max(Math.min(PARAMS.MIN_RESULTS, total), keepNRaw)
);

const finalOut = results.slice(0, keepN);

// 6) Meta
const meta = {
  inputItems: items.length,
  afterUrlDedupeAndHardExcludes: raw.length,
  clusters: clusters.length,
  biggestClusters: clusters.map(c => c.items.length).sort((a, b) => b - a).slice(0, 10),
  outputAfterKeepRatioAndCap: finalOut.length,
  params: PARAMS,
};

const output = [];

// Meta-Item
output.push({
  json: { _meta: meta },
  pairedItem: { item: 0 }
});

// Artikel
for (let i = 0; i < finalOut.length; i++) {
  output.push({
    json: finalOut[i],
    pairedItem: { item: 0 }
  });
}

return output;

// n8n Code Node (Run Once for All Items)

const PRECISION = 1;

function formatMove(name, pct) {
  const value = Number(pct);

  if (value > 0) {
    return `${name} changed by approximately +${value.toFixed(PRECISION)}%`;
  } else {
    return `${name} changed by approximately -${Math.abs(value).toFixed(PRECISION)}%`;
  }
}

const input = $input.all()[0].json;
const data = input.data;

const output = {};

for (let i = 0; i < data.length; i++) {
  const row = data[i];
  const symbol = String(row.symbol || "");
  const pct = row.priceChangePercent;

  if (symbol.startsWith("BTC")) output.BTC_change = formatMove("Bitcoin", pct);
  if (symbol.startsWith("ETH")) output.ETH_change = formatMove("Ethereum", pct);
  if (symbol.startsWith("XRP")) output.XRP_change = formatMove("XRP", pct);
  if (symbol.startsWith("SOL")) output.SOL_change = formatMove("Solana", pct);
}

return [{ json: output }];

// Parse the JSON string inside "output"
const raw = items[0].json.output;
const parsed = JSON.parse(raw);

// Transform structure
const transformed = {
  clips: parsed.clips.map(clip => ({
    news_type: clip.type,
    voiceover: clip.voiceover_text,
    image_prompt: clip.image_prompt
  }))
};

// Return clean JSON
return [
  {
    json: transformed
  }
];

const items = $input.all();

let scriptId = null;
let clips = [];
let clipIndex = 0;

for (const it of items) {
  const j = it.json;

  if (!scriptId && j.scriptId) {
    scriptId = j.scriptId;
  }

  // Intro (wenn root-level voiceover vorhanden)
  if (j.voiceover && j.image_prompt) {
    clips.push({
      clipIndex: clipIndex++,
      type: "market_overview",
      voiceover: j.voiceover,
      image_prompt: j.image_prompt
    });
  }

  // News-Clips
  if (Array.isArray(j.clips)) {
    for (const c of j.clips) {
      clips.push({
        clipIndex: clipIndex++,
        type: "news",
        voiceover: c.voiceover,
        image_prompt: c.image_prompt
      });
    }
  }
}

return [{
  json: {
    scriptId,
    clips
  },
  pairedItem: { item: 0 }
}];
